// Script Continued Below
// This Script is provided to show the changes made to UI Actions as part of the updates to all customers to add custom forms for different task types.
var grOU = new GlideRecordSecure('x_153465_discovert_discover_office_hierarchy');
grOU.query();
while(grOU.next()){
	var ouName;
	try {
		ouName = grOU.getValue("office_name");
		var parentId = grOU.getValue("parent");
		var ancestors = new OrganizationalScripts().getAncestors(parentId);
		grOU.u_all_ancestors_organizations = ancestors;
		grOU.update();
	} catch(e){
		gs.error("OU Name:" + ouName + " - Error in '2.8.1 - Fix Script - OU Ancestors' - exception: " + e);
	}
}
